//           baseMana=50, manaPerLevel=5
//           passivePerLevel: { hp:25, defense:10, damage:6 }   // per level above 10

// Rogue:    bonusHp=-10, defensePerLevel=0, bonusCritChance=10, bonusDex=8
//           baseMana=60, manaPerLevel=6
//           passivePerLevel: { critChance:2, dexterity:4, damage:5 }

// Sorcerer: bonusHp=+5,  defensePerLevel=0, bonusCritChance=0, bonusDex=0
//           baseMana=60, manaPerLevel=6
//           baseSpellPower=10, spellPowerPerFloor=0, spellPowerPerLevel=7
//           passivePerLevel: { spellPower:10, mana:8, hp:20 }

// spellPower = baseSpellPower + floor×spellPowerPerFloor + level×spellPowerPerLevel
// Sorcerer: 10 + 0×floor + 7×level
// L0=10, L5=45, L10=80, L15=115
// Deep-floor passives (>L10): +10 spellPower per level above 10
// L15 deep bonus: (15-10)×10 = +50 → total 165

function maxManaForLevel(level: number, classId?: ClassId | null): number {
  const classDef = classId ? getClassDef(classId) : null
  const base     = classDef?.baseMana     ?? 40
  const perLevel = classDef?.manaPerLevel ?? 8
  return base + level * perLevel
}

// Build fixed-width rows from class skills
const rows = Math.ceil(classSkills.length / 2)  // Warrior/Rogue: 2 rows, Sorcerer: 3 rows
const cells: (SkillDef | null)[] = [
  ...classSkills,
  ...Array(rows * 2 - classSkills.length).fill(null),  // pad to even grid
]

<View style={styles.skillGrid}>
  {cells.map((skill, i) =>
    skill
      ? <TouchableOpacity key={skill.id} style={styles.skillBtn} ...>{skill.glyph}</TouchableOpacity>
      : <View key={`empty-${i}`} style={styles.skillBtnEmpty} />
  )}
</View>

